// Prüft eine IBAN per Mod-97-Prüfsumme (ISO 13616). Kein Internet nötig.
// Eingabe: { iban: string }  →  Ausgabe: { gueltig, land, iban }
async function run(input) {
  const raw = String((input && input.iban) || '').replace(/\s+/g, '').toUpperCase();
  if (!/^[A-Z]{2}[0-9A-Z]{13,32}$/.test(raw)) return { gueltig: false, grund: 'Format ungueltig' };
  const rearranged = raw.slice(4) + raw.slice(0, 4);
  const numeric = rearranged.replace(/[A-Z]/g, c => (c.charCodeAt(0) - 55).toString());
  let remainder = 0;
  for (const d of numeric) remainder = (remainder * 10 + Number(d)) % 97;
  return { gueltig: remainder === 1, land: raw.slice(0, 2), iban: raw };
}
